#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=505;
int dp[N][N],n,m,a[150005];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
	}
	int sq=sqrt(n);
	for(int i=1;i<=sq;i++)
	{
		for(int j=1;j<=n;j++)
		{
			dp[i][j%i]+=a[j];
		}
	}
	while(m--)
	{
		int x,y;
		string s;
		cin>>s>>x>>y;
		if(s=="A")
		{
			if(x<=sq)
			{
				cout<<dp[x][y]<<"\n";
			}
			else
			{
				int sum=0;
				for(int i=y;i<=n;i+=x)
				{
					if(i==0) continue;
					sum+=a[i];
				}
				cout<<sum<<"\n";
			}
		}
		else
		{
			for(int i=1;i<=sq;i++)
			{
				dp[i][x%i]+=(y-a[x]);
			}
			a[x]=y;
		}
	}
	return 0;
}
